```plantuml
@startuml
package Bleu {
    package queue {
        class Queue {
            + New(int): Queue
            + Delete(Queue*)
            + Enqueue(Queue, uint8_t)
            + Dequeue(Queue): uint8_t
            + Add(Queue, int, const void* data)
            + Pop(Queue, int, void*)
            + Clear(Queue)
            + UsedSize(Queue)
            + AvailableSize(Queue)
        }
    }

    package heap {
        class HeapUsage {
            ~ Add(int)
            ~ Subtract(int)
            ~ WarnIfNeeded(void)
            + Get(void): int
            + Clear(void)
            + SetWarning(int, WarningDelegate)
        }
        class Heap {
            + New(int): void*
            + Delete(void**)
        }
        HeapUsage <-- Heap
    }

    package io_data {
        class IoData {
            + Write(IoAddress, IoData)
            + Add(IoAddress, IoData)
            + Remove(IoAddress, IoData)
            + Read(IoAddress): IoData
        }
    }

    package rng {
        package xorshift {
            abstract class Xorshift {
                # New(int, XorshiftAbstractMethod): Xorshift
                + Delete(Xorshift*)
                + Give(Xorshift, const uint32_t*)
                + Generate(Xorshift): uint32_t
            }
            class Xorshift32 {
                + New(void): Xorshift
            }
            class Xorshift64 {
                + New(void): Xorshift
            }
            class Xorshift96 {
                + New(void): Xorshift
            }
            class Xorshift128 {
                + New(void): Xorshift
            }
            Xorshift <|-- Xorshift32
            Xorshift <|-- Xorshift64
            Xorshift <|-- Xorshift96
            Xorshift <|-- Xorshift128
        }
        package xorshift_plus {
            abstract class XorshiftPlus {
                # New(int, XorshiftPlusAbstractMethod): XorshiftPlus
                + Delete(XorshiftPlus*)
                + Give(XorshiftPlus, const uint64_t*)
                + Generate(XorshiftPlus): uint64_t
            }
            class Xorshift128Plus {
                + New(void): XorshiftPlus
            }
            XorshiftPlus <|-- Xorshift128Plus
        }
    }

    package list {
        class ListNode {
            ~ New(const void*): ListNode
            ~ Delete(ListNode*)
            ~ GetItem(ListNode): void*
            ~ SetItem(ListNode, const void*)
            ~ GetNext(ListNode): ListNode
            ~ SetNext(ListNode, ListNode)
        }
        class List {
            + New(const void*): List
            + Delete(List*)
            + Count(List): int
            + Get(List, int): void*
            + Add(List, const void*)
            + Clear(List)
            + Find(List, const void*): void*
            + Pop(List, int): void*
            + SetItemComparer(List, ComparerInterface)
            + SetItemDeleter(List, DeleterInterface)
        }
        interface Comparer {
            + Compare(const void*, const void*): int
        }
        interface Deleter {
            + Delete(void**)
        }
        ListNode <-- List
        List --> Comparer
        List --> Deleter
    }

    Queue --> Heap
    Xorshift --> Heap
    XorshiftPlus --> Heap
    ListNode --> Heap
    List --> Heap
}
@enduml
